from typing import List
from collections import deque


class Solution:
    def orangesRotting(self, grid: List[List[int]]) -> int:
        if not grid or not grid[0]:
            return 0

        rows, cols = len(grid), len(grid[0])
        queue = deque()
        fresh_count = 0

        for r in range(rows):
            for c in range(cols):
                if grid[r][c] == 2:
                    queue.append((r, c))
                elif grid[r][c] == 1:
                    fresh_count += 1

        if fresh_count == 0:
            return 0

        minutes = 0
        directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

        while queue:
            rotted_this_layer = False
            for _ in range(len(queue)):
                row, col = queue.popleft()
                for dr, dc in directions:
                    nr, nc = row + dr, col + dc
                    if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] == 1:
                        grid[nr][nc] = 2
                        fresh_count -= 1
                        rotted_this_layer = True
                        queue.append((nr, nc))
            if rotted_this_layer:
                minutes += 1

        return minutes if fresh_count == 0 else -1


# ---- brute force oracle: repeated full-grid scan ----
class BruteSolution:
    def orangesRotting(self, grid: List[List[int]]) -> int:
        import copy
        g = copy.deepcopy(grid)
        rows, cols = len(g), len(g[0]) if g else 0
        minutes = 0
        while True:
            to_rot = []
            for r in range(rows):
                for c in range(cols):
                    if g[r][c] == 2:
                        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                            nr, nc = r+dr, c+dc
                            if 0 <= nr < rows and 0 <= nc < cols and g[nr][nc] == 1:
                                to_rot.append((nr, nc))
            if not to_rot:
                break
            for r, c in to_rot:
                g[r][c] = 2
            minutes += 1
        if any(g[r][c] == 1 for r in range(rows) for c in range(cols)):
            return -1
        return minutes


def run_tests():
    s = Solution()
    # given examples
    assert s.orangesRotting([[2,1,1],[1,1,0],[0,1,1]]) == 4
    assert s.orangesRotting([[0,2]]) == 0
    # impossible
    assert s.orangesRotting([[2,1,1],[0,1,1],[1,0,1]]) == -1
    # all empty
    assert s.orangesRotting([[0,0,0]]) == 0
    # no rotten, has fresh -> impossible
    assert s.orangesRotting([[1,1,1]]) == -1
    # single rotten
    assert s.orangesRotting([[2]]) == 0
    # single fresh
    assert s.orangesRotting([[1]]) == -1
    print("fixed tests passed")

    # randomized comparison against brute oracle
    import random
    bs = BruteSolution()
    for _ in range(3000):
        R = random.randint(1, 4)
        C = random.randint(1, 4)
        grid = [[random.choice([0,1,2]) for _ in range(C)] for _ in range(R)]
        import copy
        a = Solution().orangesRotting(copy.deepcopy(grid))
        b = bs.orangesRotting(copy.deepcopy(grid))
        assert a == b, f"MISMATCH {grid}: got {a}, oracle {b}"
    print("3000 random cases match oracle")


if __name__ == "__main__":
    run_tests()
